import{millisecondsInSecond}from"../date.js";import{getFirstTouchEventData}from"../dom.js";const DEFAULT_INITIAL_TIME=0;class UIPanGestureRecognizer{initialTime=DEFAULT_INITIAL_TIME;x1=0;y1=0;x2=0;y2=0;setInitialTimeOnce(){this.initialTime===DEFAULT_INITIAL_TIME&&(this.initialTime=Date.now())}setStartCoords(t){var{clientX:t,clientY:i}=getFirstTouchEventData(t);this.x1=t,this.y1=i}setEndCoords(t){var{clientX:t,clientY:i}=getFirstTouchEventData(t);this.x2=t,this.y2=i}delta(){return{x:this.x2-this.x1,y:this.y2-this.y1}}distance(){var{x:t,y:i}=this.delta();return Math.sqrt(Math.pow(t,2)+Math.pow(i,2))}velocity(){var t=(Date.now()-this.initialTime)/millisecondsInSecond;if(t<=0)return{x:0,y:0};var{x:i,y:e}=this.delta();return{x:i/t,y:e/t}}angle(){var t=this.x2-this.x1,i=this.y2-this.y1,i=180*Math.atan2(i,t)/Math.PI;return i<0?360+i:i}direction(){var{x:t,y:i}=this.delta();return Math.abs(t)>Math.abs(i)?{axis:"x",direction:0<t?1:t<0?-1:null}:{axis:"y",direction:0<i?1:i<0?-1:null}}reset(){this.initialTime=DEFAULT_INITIAL_TIME,this.x1=this.y1=0,this.x2=this.y2=0}}export{UIPanGestureRecognizer};